static float scada_if_score(const float raw[51]) {
  float x[51];
  for (int i=0;i<51;i++) x[i]=(raw[i]-scaler_mean[i])/scaler_scale[i];
  float avg=0.0f;
  typedef float(*fn)(const float*);
  static const fn trees[50] = {
    tree_0, tree_1, tree_2, tree_3, tree_4, tree_5, tree_6, tree_7, tree_8, tree_9, tree_10, tree_11, tree_12, tree_13, tree_14, tree_15, tree_16, tree_17, tree_18, tree_19, tree_20, tree_21, tree_22, tree_23, tree_24, tree_25, tree_26, tree_27, tree_28, tree_29, tree_30, tree_31, tree_32, tree_33, tree_34, tree_35, tree_36, tree_37, tree_38, tree_39, tree_40, tree_41, tree_42, tree_43, tree_44, tree_45, tree_46, tree_47, tree_48, tree_49
  };
  for(int i=0;i<50;i++) avg+=trees[i](x);
  avg/=(float)50;
  return -powf(2.0f,-avg/SCADA_IF_C_N)+0.5f;
}

static int scada_if_is_anomaly(const float raw[51]) {
  return scada_if_score(raw) < SCADA_IF_THRESHOLD;
}

